    private const int PageSize = 30;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "👀"];

    // State
    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private List<Message>? _messages;
    private List<ThreadSummary>? _threadSummaries;
    private string _newMessageText = "";
    private int _skip;
    private bool _loadingMore;
    private bool _allLoaded;

    // Hover & emoji picker
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadReplies;
    private string _threadReplyText = "";

    private ElementReference _messageListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        if (channel.Id == _activeChannelId) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _skip = 0;
        _allLoaded = false;
        _messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _skip = _messages.Count;
        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);
        // Refresh channel list to clear unread badge
        _channels = await ChatService.GetChannelsAsync();

        CloseThread();
    }

    private void BuildThreadSummaries()
    {
        if (_messages is null) { _threadSummaries = null; return; }

        var repliesByRoot = _messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value);

        _threadSummaries = repliesByRoot.Select(g => new ThreadSummary(
            g.Key,
            g.Count(),
            g.Max(m => m.SentAt)
        )).ToList();
    }

    // ── Pagination ──
    private async Task OnMessageListScroll()
    {
        if (_loadingMore || _allLoaded || _activeChannelId is null) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop > 50) return;

        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
        if (older.Count == 0)
        {
            _allLoaded = true;
        }
        else
        {
            _messages = [..older, ..(_messages ?? [])];
            _skip += older.Count;
            BuildThreadSummaries();
        }
        _loadingMore = false;
    }

    // ── Sending messages ──
    private async Task SendMainMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannelId is null) return;

        var msg = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
        _messages ??= [];
        _messages.Add(msg);
        _newMessageText = "";
    }

    private async Task OnMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMainMessageAsync();
        }
    }

    // ── Reactions ──
    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Reload messages to reflect new reaction
        if (_activeChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _skip > 0 ? _skip : PageSize);
        }
    }

    // ── Thread panel ──
    private async Task OpenThreadAsync(Message rootMsg)
    {
        _threadRootMessage = rootMsg;
        _threadReplies = await ChatService.GetThreadAsync(rootMsg.Id);
        _threadReplyText = "";
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;
        _threadReplyText = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootMessage is null || _activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReplyText.Trim(), _threadRootMessage.Id);
        _threadReplies ??= [];
        _threadReplies.Add(reply);
        _threadReplyText = "";

        // Also add to main list and refresh summaries
        _messages ??= [];
        _messages.Add(reply);
        BuildThreadSummaries();
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Helpers ──
    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..(maxLength - 1)] + "…";
}
