}

.message-row {
    position: relative;
    padding: 0.4rem 0.5rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-row:hover {
    background: #32353b;
}

.message-bubble {
    max-width: 100%;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
}

.message-time {
    font-size: 0.7rem;
    color: #72767d;
}

.message-content {
    margin-top: 0.15rem;
    line-height: 1.4;
    word-break: break-word;
}

/* ── Reactions ── */
.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 0.3rem;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.2rem;
    font-size: 0.8rem;
    padding: 0.1rem 0.4rem;
    background: #40444b;
    border-radius: 0.75rem;
    cursor: default;
}

/* ── Message actions ── */
.message-actions {
    position: absolute;
    top: -0.25rem;
    right: 0.5rem;
    display: flex;
    gap: 0.25rem;
    background: #2f3136;
    border: 1px solid #40444b;
    border-radius: 4px;
    padding: 0.15rem 0.25rem;
    z-index: 5;
}

.message-actions .btn {
    font-size: 0.75rem;
    padding: 0.1rem 0.4rem;
    color: #b9bbbe;
    border-color: transparent;
}

.message-actions .btn:hover {
    color: #fff;
    background: #40444b;
}

/* ── Emoji picker ── */
.emoji-picker {
    position: absolute;
    top: 100%;
    right: 0;
    background: #2f3136;
    border: 1px solid #40444b;
    border-radius: 6px;
    padding: 0.3rem;
    display: flex;
    gap: 0.15rem;
    z-index: 10;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 0.2rem 0.35rem;
    border-radius: 4px;
    line-height: 1;
}

.emoji-btn:hover {
    background: #40444b;
}

/* ── Thread link ── */
.thread-link {
    font-size: 0.8rem;
    color: #00aff4 !important;
    text-decoration: none !important;
}

.thread-link:hover {
    text-decoration: underline !important;
}

/* ── Input area ── */
.message-input-area {
    display: flex;
    gap: 0.5rem;
    padding: 0.75rem 1rem;
    border-top: 1px solid #40444b;
    background: #2f3136;
}

.message-input-area textarea {
    flex: 1;
    resize: none;
    background: #40444b;
    border: none;
    color: #dcddde;
    border-radius: 6px;
    padding: 0.5rem;
}

.message-input-area textarea::placeholder {
    color: #72767d;
}

.message-input-area textarea:focus {
    outline: none;
    box-shadow: 0 0 0 2px #5865f2;
    background: #40444b;
    color: #dcddde;
}

.send-btn {
    align-self: flex-end;
    background: #5865f2;
    border-color: #5865f2;
}

.send-btn:hover:not(:disabled) {
    background: #4752c4;
    border-color: #4752c4;
}

/* ── Thread panel ── */
.chat-thread-panel {
    width: 25%;
    min-width: 260px;
    background: #2f3136;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    border-left: 1px solid #40444b;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #40444b;
}

.thread-header h6 {
    color: #fff;
}

.thread-header .btn {
    color: #b9bbbe;
    border-color: #40444b;
    line-height: 1;
    padding: 0.15rem 0.4rem;
}

.thread-root-quote {
    padding: 0.75rem 1rem;
    background: #36393f;
    border-bottom: 1px solid #40444b;
    font-size: 0.85rem;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 0.75rem 1rem;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.thread-messages .message-bubble {
    padding: 0.3rem 0;
}
"}

