namespace sv_5b614eac00404aa1bc13ed8ce92aaa4e.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@rendermode InteractiveServer
@using sv_5b614eac00404aa1bc13ed8ce92aaa4e.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left sidebar: channel list ── *@
    <aside class="chat-sidebar">
        <h5 class="sidebar-title">Channels</h5>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var ch in _channels)
                {
                    <li class="channel-item @(ch.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(ch)">
                        <div class="channel-name"># @ch.Name</div>
                        <div class="channel-desc">@Truncate(ch.Description, 40)</div>
                        @if (ch.UnreadCount > 0)
                        {
                            <span class="badge bg-primary unread-badge">@ch.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <section class="chat-main @(_threadOpen ? "" : "chat-main-wide")">
        @if (_activeChannel is not null)
        {
            <div class="channel-header">
                <h5 class="mb-0"># @_activeChannel.Name</h5>
                <small class="text-muted">@_activeChannel.Description</small>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="OnMessageListScroll">
                @if (_loadingMore)
                {
                    <div class="text-center py-2"><small class="text-muted">Loading older messages…</small></div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-row" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => { if (_hoveredMessageId == msg.Id) _hoveredMessageId = null; }">
                            <div class="message-bubble">
                                <div class="message-header">
                                    <strong>@msg.Author</strong>
                                    <span class="message-time">@FormatRelativeTime(msg.SentAt)</span>
                                </div>
                                <div class="message-content">@msg.Content</div>

                                @if (msg.Reactions.Count > 0)
                                {
                                    <div class="reaction-row">
                                        @foreach (var r in msg.Reactions)
                                        {
                                            <span class="reaction-badge" title="@string.Join(", ", r.Users)">
                                                @r.Emoji @r.Users.Count
                                            </span>
                                        }
                                    </div>
                                }

                                @{ var thread = _threadSummaries?.FirstOrDefault(t => t.RootMessageId == msg.Id); }
                                @if (thread is not null)
                                {
                                    <button class="btn btn-link btn-sm thread-link p-0"
                                            @onclick="() => OpenThreadAsync(msg)">
                                        @thread.ReplyCount @(thread.ReplyCount == 1 ? "reply" : "replies")
                                    </button>
                                }
                            </div>

                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="btn btn-sm btn-outline-secondary" title="Reply"
                                            @onclick="() => OpenThreadAsync(msg)">
                                        💬 Reply
                                    </button>
                                    <div class="dropdown d-inline-block">
                                        <button class="btn btn-sm btn-outline-secondary"
                                                title="React"
                                                @onclick="() => ToggleEmojiPicker(msg.Id)">
                                            😀
                                        </button>
                                        @if (_emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in _commonEmojis)
                                                {
                                                    <button class="emoji-btn"
                                                            @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                        @emoji
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="form-control" rows="2" placeholder="Type a message…"
                          @bind="_newMessageText" @bind:event="oninput"
                          @onkeydown="OnMainKeyDown" />
                <button class="btn btn-primary send-btn" @onclick="SendMainMessageAsync"
                        disabled="@string.IsNullOrWhiteSpace(_newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="d-flex align-items-center justify-content-center h-100 text-muted">
                <span>Select a channel to start chatting</span>
            </div>
        }
    </section>

    @* ── Right panel: thread view ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="chat-thread-panel">
            <div class="thread-header">
                <h6 class="mb-0">Thread</h6>
                <button class="btn btn-sm btn-outline-secondary" @onclick="CloseThread" title="Close">✕</button>
            </div>

            <div class="thread-root-quote">
                <strong>@_threadRootMessage.Author</strong>
                <span class="message-time">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                <p class="mb-0 mt-1">@_threadRootMessage.Content</p>
            </div>

            <div class="thread-messages">
                @if (_threadReplies is not null)
                {
                    @foreach (var reply in _threadReplies)
                    {
                        <div class="message-bubble">
                            <div class="message-header">
                                <strong>@reply.Author</strong>
                                <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>
                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <span class="reaction-badge" title="@string.Join(", ", r.Users)">
                                            @r.Emoji @r.Users.Count
                                        </span>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="form-control" rows="2" placeholder="Reply…"
                          @bind="_threadReplyText" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDown" />
                <button class="btn btn-primary send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(_threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "👀"];

    // State
    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private List<Message>? _messages;
    private List<ThreadSummary>? _threadSummaries;
    private string _newMessageText = "";
    private int _skip;
    private bool _loadingMore;
    private bool _allLoaded;

    // Hover & emoji picker
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadReplies;
    private string _threadReplyText = "";

    private ElementReference _messageListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        if (channel.Id == _activeChannelId) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _skip = 0;
        _allLoaded = false;
        _messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _skip = _messages.Count;
        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);
        // Refresh channel list to clear unread badge
        _channels = await ChatService.GetChannelsAsync();

        CloseThread();
    }

    private void BuildThreadSummaries()
    {
        if (_messages is null) { _threadSummaries = null; return; }

        var repliesByRoot = _messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value);

        _threadSummaries = repliesByRoot.Select(g => new ThreadSummary(
            g.Key,
            g.Count(),
            g.Max(m => m.SentAt)
        )).ToList();
    }

    // ── Pagination ──
    private async Task OnMessageListScroll()
    {
        if (_loadingMore || _allLoaded || _activeChannelId is null) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop > 50) return;

        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
        if (older.Count == 0)
        {
            _allLoaded = true;
        }
        else
        {
            _messages = [..older, ..(_messages ?? [])];
            _skip += older.Count;
            BuildThreadSummaries();
        }
        _loadingMore = false;
    }

    // ── Sending messages ──
    private async Task SendMainMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannelId is null) return;

        var msg = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
        _messages ??= [];
        _messages.Add(msg);
        _newMessageText = "";
    }

    private async Task OnMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMainMessageAsync();
        }
    }

    // ── Reactions ──
    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Reload messages to reflect new reaction
        if (_activeChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _skip > 0 ? _skip : PageSize);
        }
    }

    // ── Thread panel ──
    private async Task OpenThreadAsync(Message rootMsg)
    {
        _threadRootMessage = rootMsg;
        _threadReplies = await ChatService.GetThreadAsync(rootMsg.Id);
        _threadReplyText = "";
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;
        _threadReplyText = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootMessage is null || _activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReplyText.Trim(), _threadRootMessage.Id);
        _threadReplies ??= [];
        _threadReplies.Add(reply);
        _threadReplyText = "";

        // Also add to main list and refresh summaries
        _messages ??= [];
        _messages.Add(reply);
        BuildThreadSummaries();
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Helpers ──
    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..(maxLength - 1)] + "…";
}

