toolArgs.file_text:
/* ── Layout ── */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-size: 0.9rem;
}

/* ── Sidebar ── */
.chat-sidebar {
    width: 20%;
    min-width: 200px;
    background: #2c2f33;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    overflow-y: auto;
}

.sidebar-title {
    padding: 1rem;
    margin: 0;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    font-size: 0.75rem;
    color: #8e9297;
    border-bottom: 1px solid #40444b;
}

.channel-list {
    list-style: none;
    padding: 0;
    margin: 0;
}

.channel-item {
    padding: 0.6rem 1rem;
    cursor: pointer;
    position: relative;
    border-left: 3px solid transparent;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #36393f;
}

.channel-item.active {
    background: #393c43;
    border-left-color: #5865f2;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
}

.channel-desc {
    font-size: 0.75rem;
    color: #8e9297;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    position: absolute;
    top: 0.6rem;
    right: 0.75rem;
    font-size: 0.7rem;
}

/* ── Main area ── */
.chat-main {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #36393f;
    color: #dcddde;
    transition: width 0.2s;
}

.chat-main-wide {
    width: 80%;
}

.channel-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #40444b;
    background: #2f3136;
}

.channel-header h5 {
    color: #fff;
}

/* ── Message list ── */
.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.75rem 1rem;
}

.message-row {
    position: relative;
    padding: 0.4rem 0.5rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-row:hover {
    background: #32353b;
}

.message-bubble {
    max-width: 100%;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
}

.message-time {
    font-size: 0.7rem;
    color: #72767d;
}

.message-content {
    margin-top: 0.15rem;
    line-height: 1.4;
    word-break: break-word;
}

/* ── Reactions ── */
.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 0.3rem;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.2rem;
    font-size: 0.8rem;
    padding: 0.1rem 0.4rem;
    background: #40444b;
    border-radius: 0.75rem;
    cursor: default;
}

/* ── Message actions ── */
.message-actions {
    position: absolute;
    top: -0.25rem;
    right: 0.5rem;
    display: flex;
    gap: 0.25rem;
    background: #2f3136;
    border: 1px solid #40444b;
    border-radius: 4px;
    padding: 0.15rem 0.25rem;
    z-index: 5;
}

.message-actions .btn {
    font-size: 0.75rem;
    padding: 0.1rem 0.4rem;
    color: #b9bbbe;
    border-color: transparent;
}

.message-actions .btn:hover {
    color: #fff;
    background: #40444b;
}

/* ── Emoji picker ── */
.emoji-picker {
    position: absolute;
    top: 100%;
    right: 0;
    background: #2f3136;
    border: 1px solid #40444b;
    border-radius: 6px;
    padding: 0.3rem;
    display: flex;
    gap: 0.15rem;
    z-index: 10;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 0.2rem 0.35rem;
    border-radius: 4px;
    line-height: 1;
}

.emoji-btn:hover {
    background: #40444b;
}

/* ── Thread link ── */
.thread-link {
    font-size: 0.8rem;
    color: #00aff4 !important;
    text-decoration: none !important;
}

.thread-link:hover {
    text-decoration: underline !important;
}

/* ── Input area ── */
.message-input-area {
    display: flex;
    gap: 0.5rem;
    padding: 0.75rem 1rem;
